"""matplotlib._api — internal API utilities."""

import warnings

def warn_deprecated(since, *, message='', name='', alternative='',
                    pending=False, obj_type='', addendum='', removal=''):
    warnings.warn(f'{name} is deprecated since {since}', DeprecationWarning, stacklevel=2)

def check_isinstance(_types, **kwargs):
    for k, v in kwargs.items():
        if not isinstance(v, _types):
            raise TypeError(f'{k} must be {_types}, got {type(v)}')

def check_in_list(_values, **kwargs):
    for k, v in kwargs.items():
        if v not in _values:
            raise ValueError(f'{v!r} is not in {_values}')

def check_shape(*_shapes, **kwargs):
    pass

def check_getitem(_mapping, **kwargs):
    for k, v in kwargs.items():
        if v not in _mapping:
            raise ValueError(f'{v!r} not found')
        return _mapping[v]

def classproperty(func):
    return property(func)

def delete_parameter(since, name, func=None, **kwargs):
    if func is None:
        return lambda f: f
    return func

def make_keyword_only(since, name, func=None):
    if func is None:
        return lambda f: f
    return func

def rename_parameter(since, old, new, func=None):
    if func is None:
        return lambda f: f
    return func

class deprecation:
    @staticmethod
    def deprecated(since, **kwargs):
        def decorator(obj):
            return obj
        return decorator
